      function BeforeReport return boolean is
t_ledger_id number;
begin
	SRW.USER_EXIT('FND SRWINIT');
mo_global.set_policy_context('S',:P_ORG_ID);
select ledger_id into t_ledger_id from gl_ledgers where name= mo_utils.Get_Ledger_Name( fnd_profile.value('ORG_ID'));
:P_SET_OF_BOOKS_ID := t_ledger_id;
:p_statement_date := nvl(:p_statement_date,sysdate);

--
  return (TRUE);
end;

      function AfterReport return boolean is
begin

SRW.USER_EXIT('FND SRWEXIT');  
return (TRUE);
end;

      function Report_NameFormula return VARCHAR2 is
begin

DECLARE
    l_report_name  VARCHAR2(80);
    l_follow_up_date_low  VARCHAR2 (11);
    l_follow_up_date_high VARCHAR2 (11);

BEGIN
:RP_Company_Name := :Company_Name;

 SELECT cp.user_concurrent_program_name
    INTO   l_report_name
    FROM   FND_CONCURRENT_PROGRAMS_VL cp,
           FND_CONCURRENT_REQUESTS cr
    WHERE  cr.request_id = :P_CONC_REQUEST_ID
    AND    cp.application_id = cr.program_application_id
    AND    cp.concurrent_program_id = cr.concurrent_program_id;

    :RP_Report_Name := l_report_name;
    :RP_Report_Name := 'Statement of Account';
 --   RETURN(l_report_name);
     return ('Statement of Accounts');

EXCEPTION
    WHEN NO_DATA_FOUND
    THEN :RP_REPORT_NAME := 'Statement of Account';
         RETURN('REPORT TITLE');

END;

RETURN NULL; end;

      function C_NO_DATA_FOUNDFormula return Number is
begin

:rp_data_found := :Customer_Name ;
return (0);
end;

