      function cd_total_dueFormula return Char is
begin
	
srw.reference (:Currency_Code1);
srw.reference (:total_due);
srw.user_exit (
                'FND FORMAT_CURRENCY 
                 CODE=":Currency_Code1"
                 DISPLAY_WIDTH="15"
                 AMOUNT=":total_due"
                 DISPLAY=":cd_total_due"
                 ');
return (:cd_total_due); 
