      function your_refFormula return Char is
your_ref          varchar2(200);
source_id   varchar2(15);
source_name       varchar2(50);
attribute15       varchar2(150);
begin

	begin
  	select batch_source_id into source_id
	  from   RA_CUSTOMER_TRX_ALL
	  where  CUSTOMER_TRX_ID = :CUSTOMER_TRX_ID;
	exception
		when others then
		  your_ref := 'Error 1';
	end;

	begin
	    select name, attribute15 into source_name, attribute15
	    from   RA_BATCH_SOURCES_ALL
   	  where  batch_source_id = source_id;
   	--  srw.message(10,source_name);
		exception
		when others then
		  your_ref := 'Error 2';
	end;
  /* commented for SR 171367 
	if source_name = 'Adhoc' or source_name = 'Adhoc Recurring' or 
		             source_name = 'PAX - RAPID' or source_name = 'Cargo - RAPID' or 
		             source_name = 'OBAR' or source_name = 'Adhoc Standard Import' then
	commented for SR 171367 */
		             
  if 	source_name in( 'Adhoc', 'Adhoc Recurring', 'PAX - RAPID', 'Cargo - RAPID', 'OBAR', 'Adhoc Standard Import','SLL MIGRATION') then -- Added for SR 171367
  	    your_ref := :y_ref;
	elsif source_name = 'GL' then
		    your_ref := 'Recharge';
	elsif
--		    your_ref := source_name;
--	end if;
	   source_name = 'PRA Auditors' then
	   
    	begin 
    --  srw.message(20,'Inside PRA');
	      	 select nvl(iih.HDR_LPO_NUMBER,rtt.description)
	      	      into your_ref
	      	 from   ips_invoice_header iih,
	      	 				ra_customer_trx_all rct,
	      	 				ra_cust_trx_types_all rtt
	      	 where  
	      	 iih.invoice_num = rct.trx_number
	     AND rct.CUSTOMER_TRX_ID=:CUSTOMER_TRX_ID
	     AND rct.CUST_TRX_TYPE_ID = rtt.CUST_TRX_TYPE_ID;
	      	 --AND CUST_TRX_TYPE_ID = :CUST_TRX_TYPE_ID;
	      --	 srw.message(30,'Outside PRA');
--      	end if;
      	exception
      		when others then
		          your_ref := source_name;
		         -- srw.message(40,'Gone Inside!! Oops Exception');
      	end;
	else
--		    your_ref := source_name;
--	end if;
	
    	begin 
--      	if source_name = 'Cargo Hndlng' then
	      	 select description into your_ref
	      	 from   RA_CUST_TRX_TYPES_ALL
	      	 where  CUST_TRX_TYPE_ID = :CUST_TRX_TYPE_ID;
--      	end if;
      	exception
      		when others then
		          your_ref := source_name;
		        --  srw.message(10,'Gone Inside!! Oops Exception');
    	end;      	
  end if;
  if :tran_type = 'PMT' then
  	your_ref := :invoice_number;
  end if;
  
	return (your_ref);
	
	exception
		when others then
	     return ('Error');
  
end;

