      function add1Formula return Char is
add1   varchar2(250);
begin
  SELECT loc.address1, loc.address2, loc.address3, loc.city, loc.country
  into   add1, :add2, :add3, :site_city, :site_country
  FROM   HZ_CUST_ACCT_SITES_all ACCT_SITE, 
         HZ_PARTY_SITES PARTY_SITE, 
         HZ_LOCATIONS LOC, 
         HZ_CUST_SITE_USES_ALL SITE_USES
  where  ACCT_SITE.CUST_ACCT_SITE_ID = SITE_USES.CUST_ACCT_SITE_ID 
  AND    ACCT_SITE.PARTY_SITE_ID = PARTY_SITE.PARTY_SITE_ID 
  AND    LOC.LOCATION_ID = PARTY_SITE.LOCATION_ID;
--  and    site_uses.SITE_USE_ID = :site_id;
  
      return (add1);
      
exception
	  when others then
	     add1 := :address1;
	    :add2 := :address2;
	    :add3 := :address3;
	    :site_city := :city;
	    :site_country := :country;
	    
	      return (add1);

end;

      function country_descFormula return Char is
country    varchar2(500);
begin
  select name into country 
  from PA_COUNTRY_V
  where  country_code = :site_country;
  
  return (country);
  
exception
	when others then
	  return (:country);
end;

      function inv_numberFormula return Char is
inv_number    varchar2(50);
begin
	
  if :tran_type = 'PMT' then
  	 select DOC_SEQUENCE_VALUE into inv_number
  	 from   ar_cash_receipts_all
  	 where  receipt_number = :invoice_number;
  else
  	inv_number := :invoice_number;
  end if;
    return (nvl(:invoice_number,inv_number));
    -- return (inv_number);
     
  exception
  	when others then
  	   return(:invoice_number);
  	  
end;

