      function inv_amt_orig_txtFormula return Char is
format_amt VARCHAR2(20);
begin

  
  if ((:Currency_Code1 = 'IRR') or
       (:Currency_Code1 = 'IDR') or
       (:Currency_Code1 = 'TZS') OR
        (:Currency_Code1 = 'LBP')) THEN
       select to_char(:inv_amt_orig,'999999999999990') into format_amt from dual;
      -- SRW.SET_FIELD_NUM(:inv_amt_orig,format_amt);
       
       
  elsif
  	  ((:Currency_Code1 = 'OMR') or
       (:Currency_Code1 = 'BHD') or
       (:Currency_Code1 = 'KWD') OR
        (:Currency_Code1 = 'JOD')) THEN
       select to_char(:inv_amt_orig,'999999999990.000') into format_amt from dual;
      -- SRW.SET_FIELD_NUM(:inv_amt_orig,format_amt);
       
  ELSE
  	  select to_char(:inv_amt_orig,'9999999999990.00') into format_amt from dual;
       --SRW.SET_FIELD_NUM(:inv_amt_orig,format_amt);
  end if;
  
  return trim(format_amt); 

 -- return (TRUE);
end;

